19	export function getDb(): Database {
20	  if (!_db) {
21	    _db = new Database(SESSIONS_DB_PATH, { create: true });
22	    _db.exec("PRAGMA journal_mode=WAL");
23	    _db.exec("PRAGMA foreign_keys=ON");
24	    _db.exec("PRAGMA busy_timeout=10000"); // wait up to 10s instead of failing immediately
25	  }
26	  return _db;
27	}
