123	      date(u.timestamp) AS date,
124	      u.content AS user_content,
125	      u.timestamp AS user_ts,
126	      (
127	        SELECT a.content FROM turns a
128	        WHERE a.session_id = u.session_id
129	          AND a.role = 'assistant'
130	          AND a.turn_index > u.turn_index
131	          AND a.turn_index < COALESCE(
132	            (SELECT MIN(u2.turn_index) FROM turns u2
133	             WHERE u2.session_id = u.session_id
134	               AND u2.role = 'user'
135	               AND u2.turn_index > u.turn_index),
136	            999999)
137	        ORDER BY a.turn_index DESC LIMIT 1
138	      ) AS assistant_final,
139	      (
140	        SELECT a.timestamp FROM turns a
141	        WHERE a.session_id = u.session_id
142	          AND a.role = 'assistant'
143	          AND a.turn_index > u.turn_index
144	          AND a.turn_index < COALESCE(
145	            (SELECT MIN(u2.turn_index) FROM turns u2
146	             WHERE u2.session_id = u.session_id
147	               AND u2.role = 'user'
148	               AND u2.turn_index > u.turn_index),
149	            999999)
150	        ORDER BY a.turn_index DESC LIMIT 1
151	      ) AS assistant_ts
152	    FROM turns u
153	    JOIN sessions s ON s.id = u.session_id
154	    WHERE u.role = 'user' AND u.turn_kind = 'human_input';
155	  `);
