220	// ── Upsert session + turns ────────────────────────────────────────────────────
221	
222	export function upsertSession(
223	  session: Session,
224	  turns: Turn[],
225	  filePath: string,
226	): Promise<void> {
227	  return serializeWrite(() => _upsertSessionSync(session, turns, filePath));
228	}
229	
230	function _upsertSessionSync(
231	  session: Session,
232	  turns: Turn[],
233	  filePath: string,
234	): void {
235	  const db = getDb();
236	
237	  const insertSession = db.prepare(`
238	    INSERT OR REPLACE INTO sessions
239	      (id, tool, project, cwd, started_at, ended_at, turn_count, human_turn_count,
240	       model, source_file, input_tokens, output_tokens, cache_creation_tokens,
241	       cache_read_tokens, tool_call_count, tool_call_names)
242	    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
243	  `);
244	
245	  const deleteTurns = db.prepare("DELETE FROM turns WHERE session_id = ?");
246	
247	  const insertTurn = db.prepare(`
248	    INSERT OR REPLACE INTO turns
249	      (id, session_id, role, turn_kind, content, timestamp, turn_index,
250	       tool_calls, tool_names, input_tokens, output_tokens,
251	       cache_creation_tokens, cache_read_tokens)
252	    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
253	  `);
254	
255	  const upsertSync = db.prepare(`
256	    INSERT OR REPLACE INTO sync_state (source_file, mtime, size, synced_at)
257	    VALUES (?, ?, ?, ?)
258	  `);
259	
260	  const markStale = db.prepare(`
261	    UPDATE daily_digest SET stale = 1
262	    WHERE date = date(?) AND stale = 0
263	  `);
264	
265	  db.transaction(() => {
266	    insertSession.run(
267	      session.id,
268	      session.tool,
269	      session.project,
270	      session.cwd,
271	      session.started_at,
272	      session.ended_at,
273	      session.turn_count,
274	      session.human_turn_count,
275	      session.model,
276	      session.source_file,
277	      session.input_tokens,
278	      session.output_tokens,
279	      session.cache_creation_tokens,
280	      session.cache_read_tokens,
281	      session.tool_call_count,
282	      JSON.stringify(session.tool_call_names),
283	    );
284	
285	    deleteTurns.run(session.id);
286	
287	    for (const t of turns) {
288	      insertTurn.run(
289	        t.id,
290	        t.session_id,
291	        t.role,
292	        t.turn_kind,
293	        t.content,
294	        t.timestamp,
295	        t.turn_index,
296	        t.tool_calls,
297	        JSON.stringify(t.tool_names),
298	        t.input_tokens,
299	        t.output_tokens,
300	        t.cache_creation_tokens,
301	        t.cache_read_tokens,
302	      );
303	    }
304	
305	    // Update sync state
306	    const stat = statSync(filePath);
307	    upsertSync.run(filePath, stat.mtimeMs, stat.size, new Date().toISOString());
308	
309	    // Mark digest stale for affected dates
310	    if (session.started_at) {
311	      markStale.run(session.started_at);
312	    }
313	    if (session.ended_at && session.ended_at !== session.started_at) {
314	      markStale.run(session.ended_at);
315	    }
316	  })();
317	}
