319	// ── File change detection ─────────────────────────────────────────────────────
320	
321	export function fileChanged(filePath: string): boolean {
322	  const db = getDb();
323	  const row = db
324	    .query<{ mtime: number; size: number }, [string]>(
325	      "SELECT mtime, size FROM sync_state WHERE source_file = ?",
326	    )
327	    .get(filePath);
328	
329	  if (!row) return true;
330	
331	  try {
332	    const stat = statSync(filePath);
333	    return stat.mtimeMs !== row.mtime || stat.size !== row.size;
334	  } catch {
335	    return true;
336	  }
337	}
