12	// Track dates currently being generated to avoid duplicate LLM calls
13	const _generatingDates = new Set<string>();
14	type SqlParam = string | number | bigint | boolean | null | Uint8Array;
15	
16	function json(data: unknown, status = 200): Response {
17	  return new Response(JSON.stringify(data), {
18	    status,
19	    headers: {
20	      "Content-Type": "application/json",
21	      "Access-Control-Allow-Origin": "*",
22	    },
23	  });
24	}
