35	export async function handleRequest(req: Request): Promise<Response | null> {
36	  const url = new URL(req.url);
37	  const path = url.pathname;
38	  const q = url.searchParams;
39	
40	  // ── Manual sync ─────────────────────────────────────────────────────────────
41	  if (path === "/api/sessions/sync" && req.method === "GET") {
42	    const date = q.get("date");
43	    const result = date ? await runSyncForDate(date) : await runSync();
44	    return json(result);
45	  }
46	
47	  // ── Digest list ──────────────────────────────────────────────────────────────
48	  if (path === "/api/sessions/digest/list" && req.method === "GET") {
49	    const db = getDb();
50	    const rows = db
51	      .query("SELECT date, pair_count, model, mock, generated_at, stale FROM daily_digest ORDER BY date DESC")
52	      .all();
53	    return json({ digests: rows });
54	  }
55	
56	  // ── Digest missing ───────────────────────────────────────────────────────────
57	  if (path === "/api/sessions/digest/missing" && req.method === "GET") {
58	    const dates = findDatesMissingDigest();
59	    return json({ missing_dates: dates, count: dates.length });
60	  }
61	
62	  // ── Digest backfill ──────────────────────────────────────────────────────────
63	  if (path === "/api/sessions/digest/backfill" && (req.method === "POST" || req.method === "GET")) {
64	    const force = q.get("force") === "true";
65	    const result = await backfillDigests(force);
66	    return json(result);
67	  }
68	
69	  // ── Digest for date ──────────────────────────────────────────────────────────
70	  // LLM calls can take 30-120s. Strategy:
71	  // - If cached (stale=0) and not force: return immediately
72	  // - Otherwise: kick off background generation, return {generating:true} immediately
73	  // - Frontend polls until generating:false
74	  if (path === "/api/sessions/digest" && req.method === "GET") {
75	    const date = q.get("date") ?? new Date().toISOString().slice(0, 10);
76	    const force = q.get("force") === "true";
77	
78	    // Check cache first
79	    if (!force) {
80	      const db = getDb();
81	      const cached = db
82	        .query<{ summary: string; pair_count: number; model: string; mock: number; generated_at: string; stale: number }, [string]>(
83	          "SELECT * FROM daily_digest WHERE date = ? AND stale = 0",
84	        )
85	        .get(date);
86	      if (cached) {
87	        return json({
88	          date,
89	          summary: cached.summary,
90	          pair_count: cached.pair_count,
91	          model: cached.model,
92	          mock: cached.mock === 1,
93	          generated_at: cached.generated_at,
94	          stale: false,
95	          cached: true,
96	          generating: false,
97	        });
98	      }
99	    }
100	
101	    // Check if already generating
102	    if (_generatingDates.has(date)) {
103	      return json({ date, summary: null, pair_count: 0, model: "", mock: true, generated_at: null, stale: false, cached: false, generating: true });
104	    }
105	
106	    // Start background generation
107	    _generatingDates.add(date);
108	    generateDigest(date, force)
109	      .catch((e) => console.warn(`[digest] Background generation failed for ${date}: ${e?.message}`))
110	      .finally(() => _generatingDates.delete(date));
111	
112	    return json({ date, summary: null, pair_count: 0, model: "", mock: true, generated_at: null, stale: false, cached: false, generating: true });
113	  }
114	
115	  // ── Daily summary ────────────────────────────────────────────────────────────
116	  if (path === "/api/sessions/summary" && req.method === "GET") {
117	    const date = q.get("date") ?? new Date().toISOString().slice(0, 10);
118	    const dateStart = `${date}T00:00:00`;
119	    const dateEnd = `${date}T23:59:59`;
120	
121	    const db = getDb();
122	    const rows = db
123	      .query<
124	        { tool: string; session_count: number; turn_count: number; projects: string },
125	        [string, string]
126	      >(`
127	        SELECT tool, COUNT(*) as session_count, SUM(turn_count) as turn_count,
128	               GROUP_CONCAT(DISTINCT project) as projects
129	        FROM sessions
130	        WHERE started_at BETWEEN ? AND ?
131	        GROUP BY tool
132	      `)
133	      .all(dateStart, dateEnd);
134	
135	    const totalSessions = rows.reduce((s, r) => s + r.session_count, 0);
136	    const totalTurns = rows.reduce((s, r) => s + (r.turn_count ?? 0), 0);
137	    const byTool: Record<string, { sessions: number; turns: number; projects: string[] }> = {};
138	    for (const r of rows) {
139	      byTool[r.tool] = {
140	        sessions: r.session_count,
141	        turns: r.turn_count ?? 0,
142	        projects: (r.projects ?? "").split(",").filter(Boolean),
143	      };
144	    }
145	
146	    return json({ date, total_sessions: totalSessions, total_turns: totalTurns, by_tool: byTool });
147	  }
148	
149	  // ── Session list ─────────────────────────────────────────────────────────────
150	  if (path === "/api/sessions" && req.method === "GET") {
151	    const tool = q.get("tool");
152	    const date = q.get("date");
153	    const project = q.get("project");
154	    const limit = Math.min(parseInt(q.get("limit") ?? "50"), 200);
155	    const offset = parseInt(q.get("offset") ?? "0");
156	
157	    const db = getDb();
158	    const filterConds: string[] = [];
159	    const filterParams: SqlParam[] = [];
160	    if (tool) { filterConds.push("s.tool = ?"); filterParams.push(tool); }
161	    if (project) { filterConds.push("s.project = ?"); filterParams.push(project); }
162	    const filterSql = filterConds.length ? "AND " + filterConds.join(" AND ") : "";
163	
164	    let rows: any[], total: number;
165	
166	    if (date) {
167	      const dateParams = [...filterParams, date, `${date}T00:00:00`, `${date}T23:59:59`];
168	      const whereSql = `
169	        WHERE 1=1 ${filterSql}
170	          AND (
171	            date(s.started_at) = ?
172	            OR EXISTS (
173	              SELECT 1 FROM turns t
174	              WHERE t.session_id = s.id
175	                AND t.timestamp BETWEEN ? AND ?
176	            )
177	          )
178	      `;
179	      total = (db.query<{ cnt: number }, SqlParam[]>(
180	        `SELECT COUNT(DISTINCT s.id) as cnt FROM sessions s ${whereSql}`,
181	      ).get(...dateParams) as any)?.cnt ?? 0;
182	      rows = db.query(
183	        `SELECT DISTINCT s.* FROM sessions s ${whereSql} ORDER BY COALESCE(s.ended_at, s.started_at) DESC LIMIT ? OFFSET ?`,
184	      ).all(...dateParams, limit, offset) as any[];
185	    } else {
186	      const where = filterConds.length
187	        ? "WHERE " + filterConds.map((c) => c.replace("s.", "")).join(" AND ")
188	        : "";
189	      total = (db.query<{ cnt: number }, SqlParam[]>(
190	        `SELECT COUNT(*) as cnt FROM sessions ${where}`,
191	      ).get(...filterParams) as any)?.cnt ?? 0;
192	      rows = db.query(
193	        `SELECT * FROM sessions ${where} ORDER BY COALESCE(ended_at, started_at) DESC LIMIT ? OFFSET ?`,
194	      ).all(...filterParams, limit, offset) as any[];
195	    }
196	
197	    const sessions = rows.map((r: any) => ({
198	      ...r,
199	      tool_call_names: parseJsonField(r.tool_call_names, {}),
200	    }));
201	
202	    return json({ sessions, total, limit, offset });
203	  }
204	
205	  // ── Session turns ────────────────────────────────────────────────────────────
206	  const turnsMatch = path.match(/^\/api\/sessions\/([^/]+)\/turns$/);
207	  if (turnsMatch && req.method === "GET") {
208	    const sessionId = decodeURIComponent(turnsMatch[1]);
209	    const date = q.get("date");
210	    const db = getDb();
211	
212	    const sessionRow = db.query("SELECT * FROM sessions WHERE id = ?").get(sessionId) as any;
213	    if (!sessionRow) return json({ error: "session not found" }, 404);
214	
215	    let turns: any[];
216	    if (date) {
217	      turns = db
218	        .query("SELECT * FROM turns WHERE session_id = ? AND date(timestamp) = ? ORDER BY turn_index")
219	        .all(sessionId, date) as any[];
220	    } else {
221	      turns = db
222	        .query("SELECT * FROM turns WHERE session_id = ? ORDER BY turn_index")
223	        .all(sessionId) as any[];
224	    }
225	
226	    const session = {
227	      ...sessionRow,
228	      tool_call_names: parseJsonField(sessionRow.tool_call_names, {}),
229	    };
230	
